// Inicializa estado para paginação de Contas a Pagar
// IMPORTANTE: substitua pelos seus valores reais
// Alternativa segura: use $env.OMIE_APP_KEY e $env.OMIE_APP_SECRET
const APP_KEY = '5702108297886';
const APP_SECRET = '3471e4c77c8f78172edbbf79c9ee4c34';

return [{
  json: {
    app_key: APP_KEY,
    app_secret: APP_SECRET,
    pagina_atual: 1,
    registros_por_pagina: 500,
    endpoint: 'https://app.omie.com.br/api/v1/financas/contapagar/',
    call: 'ListarContasPagar',
    tipo: 'conta_pagar_cadastro',
    todos_registros: []
  }
}];

// Processa página retornada e acumula registros
const inputData = $('Config Contas a Pagar').first().json;
const resposta = $input.first().json;

// Extrair registros da página atual
const registrosPagina = resposta[inputData.tipo] || [];

// Acumular com registros anteriores
const todosRegistros = [...inputData.todos_registros, ...registrosPagina];

const paginaAtual = resposta.pagina || inputData.pagina_atual;
const totalPaginas = resposta.total_de_paginas || 1;
const totalRegistros = resposta.total_de_registros || 0;

return [{
  json: {
    app_key: inputData.app_key,
    app_secret: inputData.app_secret,
    pagina_atual: paginaAtual,
    total_de_paginas: totalPaginas,
    total_de_registros: totalRegistros,
    registros_coletados: todosRegistros.length,
    registros_por_pagina: inputData.registros_por_pagina,
    endpoint: inputData.endpoint,
    call: inputData.call,
    tipo: inputData.tipo,
    todos_registros: todosRegistros,
    tem_mais_paginas: paginaAtual < totalPaginas
  }
}];

// Incrementa página e prepara próxima requisição
const input = $input.first().json;

return [{
  json: {
    app_key: input.app_key,
    app_secret: input.app_secret,
    pagina_atual: input.pagina_atual + 1,
    registros_por_pagina: input.registros_por_pagina,
    endpoint: input.endpoint,
    call: input.call,
    tipo: input.tipo,
    todos_registros: input.todos_registros
  }
}];

// Achata os dados para formato tabular (CSV-ready)
const input = $input.first().json;
const registros = input.todos_registros;

if (!registros || registros.length === 0) {
  return [{ json: { erro: 'Nenhum registro de contas a pagar encontrado', total_esperado: input.total_de_registros, total_coletado: 0 } }];
}

console.log(`Contas a Pagar: ${registros.length} de ${input.total_de_registros} registros`);

if (registros.length !== input.total_de_registros) {
  console.warn(`ATENCAO: Esperados ${input.total_de_registros}, coletados ${registros.length}`);
}

return registros.map(reg => {
  const categoria = reg.categorias && reg.categorias[0] ? reg.categorias[0] : {};
  const distribuicao = reg.distribuicao && reg.distribuicao[0] ? reg.distribuicao[0] : {};

  return {
    json: {
      codigo_lancamento_omie: reg.codigo_lancamento_omie || '',
      codigo_lancamento_integracao: reg.codigo_lancamento_integracao || '',
      codigo_cliente_fornecedor: reg.codigo_cliente_fornecedor || '',
      data_vencimento: reg.data_vencimento || '',
      data_emissao: reg.data_emissao || '',
      data_entrada: reg.data_entrada || '',
      data_previsao: reg.data_previsao || '',
      valor_documento: reg.valor_documento || 0,
      valor_titulo: reg.valor_titulo || 0,
      codigo_categoria: reg.codigo_categoria || categoria.codigo_categoria || '',
      categoria_descricao: categoria.descricao || '',
      status_titulo: reg.status_titulo || '',
      codigo_tipo_documento: reg.codigo_tipo_documento || '',
      numero_documento: reg.numero_documento || '',
      numero_parcela: reg.numero_parcela || '',
      observacao: reg.observacao || '',
      id_conta_corrente: reg.id_conta_corrente || '',
      bloqueado: reg.bloqueado || '',
      baixa_bloqueada: reg.baixa_bloqueada || '',
      importado_api: reg.importado_api || '',
      id_origem: reg.id_origem || '',
      operacao: reg.operacao || '',
      valor_pis: distribuicao.valor_pis || 0,
      valor_cofins: distribuicao.valor_cofins || 0,
      valor_csll: distribuicao.valor_csll || 0,
      valor_icms: distribuicao.valor_icms || 0,
      valor_iss: distribuicao.valor_iss || 0
    }
  };
});

// Inicializa estado para paginação de Contas a Receber
